import { useEffect,useState } from "react";
import API from "../services/api"
export default function Jobs()
{
    const [job,setJob] = useState(null)
    useEffect(() => {
        const fetchRecommendation = async () => {
            try{
                const token =localStorage.getItem("token")
                const res = await API.get("/jobs/recommend", {
                    headers: {
                        Authorization : `Bearer ${token}`
                    }
                })
                setJob(res.data)
            } catch(error)
            {
                console.log(error)
            }
        }
        fetchRecommendation()
    },{})
    return (
  <div style={{ padding: "20px" }}>
    <h2>Job Recommendation</h2>

    {job ? (
      <div style={{
        border: "1px solid #ccc",
        borderRadius: "10px",
        padding: "20px",
        width: "300px",
        marginTop: "20px",
        boxShadow: "0 4px 8px rgba(0,0,0,0.1)"
      }}>
        <h3>{job.recommendedRole}</h3>
        <p><strong>Match Score:</strong> {job.matchScore}</p>

        <button style={{
          marginTop: "10px",
          padding: "8px 12px",
          border: "none",
          backgroundColor: "#4CAF50",
          color: "white",
          borderRadius: "5px",
          cursor: "pointer"
        }}>
          Save Job
        </button>

      </div>
    ) : (
      <p>Loading...</p>
    )}
  </div>
)
}
